patch:
diff --git a/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h b/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
index ee3cc950cdb5..5ffe68bd6da9 100644
--- a/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
+++ b/llvm/include/llvm/Transforms/Utils/SimplifyCFGOptions.h
@@ -23,7 +23,7 @@ class AssumptionCache;
 struct SimplifyCFGOptions {
   int BonusInstThreshold = 1;
   bool ForwardSwitchCondToPhi = false;
-  bool ConvertSwitchRangeToICmp = false;
+  bool ConvertSwitchRangeToICmp = true;
   bool ConvertSwitchToLookupTable = false;
   bool NeedCanonicalLoop = true;
   bool HoistCommonInsts = false;
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 48055ad6ea7e..c5f838dacd89 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5816,6 +5816,9 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
   SmallVectorImpl<ConstantInt *> *ContiguousCases = nullptr;
   BasicBlock *ContiguousDest = nullptr;
   BasicBlock *OtherDest = nullptr;
+  SmallVector<ConstantInt *, 16> ComplementCasesVec;
+  uint64_t ComplementSize = 0;
+  bool UseComplement = false;
   if (!CasesA.empty() && casesAreContiguous(CasesA)) {
     ContiguousCases = &CasesA;
     ContiguousDest = DestA;
@@ -5824,14 +5827,109 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,
     ContiguousCases = &CasesB;
     ContiguousDest = DestB;
     OtherDest = DestA;
+  } else if (!CasesA.empty() || !CasesB.empty()) {
+    // Try to see if the complement of one set of cases within a known range
+    // is contiguous.
+    Value *Cond = SI->getCondition();
+    std::optional<ConstantRange> CR;
+    if (auto *Arg = dyn_cast<Argument>(Cond))
+      CR = Arg->getRange();
+    else if (auto *CB = dyn_cast<CallBase>(Cond))
+      CR = CB->getRange();
+    else if (auto *I = dyn_cast<Instruction>(Cond)) {
+      if (const MDNode *Ranges = I->getMetadata(LLVMContext::MD_range)) {
+        // Use the first range from the metadata (conservatively).
+        if (Ranges->getNumOperands() >= 2) {
+          ConstantInt *Lower = mdconst::extract<ConstantInt>(Ranges->getOperand(0));
+          ConstantInt *Upper = mdconst::extract<ConstantInt>(Ranges->getOperand(1));
+          CR = ConstantRange(Lower->getValue(), Upper->getValue());
+        }
+      }
+    }
+
+    if (!CR || CR->isFullSet() || CR->isEmptySet())
+      return false;
+
+    APInt Low = CR->getLower();
+    APInt High = CR->getUpper();
+
+    // Choose the set whose complement we'll try to make contiguous.
+    // If CasesA is empty, the values going to DestA are just the default set
+    // (everything in range except CasesB). We'll check if that set is contiguous.
+    SmallVectorImpl<ConstantInt *> *CandidateCases = nullptr;
+    BasicBlock *CandidateDest = nullptr;
+    BasicBlock *ComplementDest = nullptr;
+    bool ComplementIsDefault = false;
+
+    if (CasesA.empty() && !CasesB.empty()) {
+      CandidateCases = &CasesB;
+      CandidateDest = DestB;
+      ComplementDest = DestA;
+      ComplementIsDefault = HasDefault;
+    } else if (CasesB.empty() && !CasesA.empty()) {
+      CandidateCases = &CasesA;
+      CandidateDest = DestA;
+      ComplementDest = DestB;
+      ComplementIsDefault = false;
+    } else {
+      return false;
+    }
+
+    // Sort the candidate cases.
+    SmallVector<APInt, 16> Sorted;
+    for (auto *CI : *CandidateCases)
+      Sorted.push_back(CI->getValue());
+    llvm::sort(Sorted, [](const APInt &A, const APInt &B) { return A.ult(B); });
+
+    // Compute intervals of the complement within [Low, High).
+    struct Interval {
+      APInt Start; // inclusive
+      APInt End;   // exclusive
+    };
+    SmallVector<Interval, 4> Intervals;
+
+    APInt Cur = Low;
+    for (const APInt &V : Sorted) {
+      if (Cur.ult(V)) {
+        Intervals.push_back({Cur, V});
+      }
+      // Move past this value.
+      if (V == APInt::getMaxValue(V.getBitWidth()))
+        Cur = High; // overflow, we're done
+      else
+        Cur = V + 1;
+    }
+    if (Cur.ult(High)) {
+      Intervals.push_back({Cur, High});
+    }
+
+    if (Intervals.size() != 1)
+      return false;
+
+    // The complement is a single contiguous interval.
+    APInt Start = Intervals[0].Start;
+    APInt End = Intervals[0].End;
+    if (Start == End)
+      return false;
+    (void)(End - Start);
+
+    // Create a minimal vector for the contiguous complement cases.
+    // We need back() to return the smallest value of the complement range.
+    ComplementCasesVec.clear();
+    ComplementCasesVec.push_back(cast<ConstantInt>(ConstantInt::get(Cond->getType(), Start)));
+    ContiguousCases = &ComplementCasesVec;
+    ContiguousDest = ComplementDest;
+    OtherDest = CandidateDest;
+    ComplementSize = (End - Start).getZExtValue();
+    UseComplement = true;
   } else
     return false;

   // Start building the compare and branch.

   Constant *Offset = ConstantExpr::getNeg(ContiguousCases->back());
-  Constant *NumCases =
-      ConstantInt::get(Offset->getType(), ContiguousCases->size());
+  Constant *NumCases = ConstantInt::get(Offset->getType(),
+      UseComplement ? ComplementSize : ContiguousCases->size());

   Value *Sub = SI->getCondition();
   if (!Offset->isNullValue())
@@ -5869,16 +5967,29 @@ bool SimplifyCFGOpt::turnSwitchRangeIntoICmp(SwitchInst *SI,

   // Prune obsolete incoming values off the successors' PHI nodes.
   for (auto BBI = ContiguousDest->begin(); isa<PHINode>(BBI); ++BBI) {
-    unsigned PreviousEdges = ContiguousCases->size();
-    if (ContiguousDest == SI->getDefaultDest())
-      ++PreviousEdges;
+    unsigned PreviousEdges;
+    if (UseComplement) {
+      // Complement values all go to the default destination via the single
+      // default edge.
+      PreviousEdges = 1;
+    } else {
+      PreviousEdges = ContiguousCases->size();
+      if (ContiguousDest == SI->getDefaultDest())
+        ++PreviousEdges;
+    }
     for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
       cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
   }
   for (auto BBI = OtherDest->begin(); isa<PHINode>(BBI); ++BBI) {
-    unsigned PreviousEdges = SI->getNumCases() - ContiguousCases->size();
-    if (OtherDest == SI->getDefaultDest())
-      ++PreviousEdges;
+    unsigned PreviousEdges;
+    if (UseComplement) {
+      // All explicit cases go to OtherDest.
+      PreviousEdges = SI->getNumCases();
+    } else {
+      PreviousEdges = SI->getNumCases() - ContiguousCases->size();
+      if (OtherDest == SI->getDefaultDest())
+        ++PreviousEdges;
+    }
     for (unsigned I = 0, E = PreviousEdges - 1; I != E; ++I)
       cast<PHINode>(BBI)->removeIncomingValue(SI->getParent());
   }

